+// deno-lint-ignore-file no-explicit-any
+import { join, resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths?.length ? options.searchPaths : [cwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  const matches: Array<{ path: string; values: Record<string, unknown> }> = [];
+
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const path = resolve(searchPath, fileName(options.name, format));
+      const content = await readIfExists(path);
+      if (content === undefined) continue;
+      matches.push({ path, values: parseConfig(path, content, format, options.parser) });
+      if (!options.mergeConfigs) {
+        return { path, values: flattenConfig(matches[0].values) };
+      }
+      break;
+    }
+  }
+
+  // Earlier paths win, while values in a single file retain their natural order.
+  const values: Record<string, unknown> = {};
+  for (const match of matches.slice().reverse()) {
+    Object.assign(values, flattenConfig(match.values));
+  }
+  return { path: matches[0]?.path, values };
+}
+
+function fileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function parseConfig(
+  path: string,
+  content: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const value = parser
+      ? parser(content)
+      : format === ".json"
+      ? JSON.parse(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : (() => { throw new Error(`No parser for "${format}" files.`); })();
+    if (!isPlainObject(value)) throw new Error("Config must contain a plain object.");
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const equals = line.indexOf("=");
+    if (equals < 1) throw new Error(`Invalid RC line: "${rawLine}"`);
+    const key = line.slice(0, equals).trim();
+    let value = line.slice(equals + 1).trim();
+    if (/^".*"$/.test(value)) {
+      values[key] = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      values[key] = value === "true";
+    } else if (/^[+-]?(?:\\d+\\.?\\d*|\\.\\d+)(?:e[+-]?\\d+)?$/i.test(value)) {
+      values[key] = Number(value);
+    } else {
+      values[key] = value;
+    }
+  }
+  return values;
+}
+
+export function flattenConfig(value: Record<string, unknown>): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  const visit = (input: Record<string, unknown>, prefix = "") => {
+    for (const [rawKey, item] of Object.entries(input)) {
+      const key = rawKey.replace(/-([a-z])/g, (_, char: string) => char.toUpperCase());
+      const name = prefix ? `${prefix}.${key}` : key;
+      if (isPlainObject(item)) visit(item, name);
+      else result[name] = item;
+    }
+  };
+  visit(value);
+  return result;
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (!value || typeof value !== "object" || Array.isArray(value)) return false;
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
+
+function cwd(): string {
+  const runtime = globalThis as any;
+  return runtime.Deno?.cwd() ?? runtime.process?.cwd() ?? ".";
+}
+
+async function readIfExists(path: string): Promise<string | undefined> {
+  try {
+    const runtime = globalThis as any;
+    if (runtime.Deno) return await runtime.Deno.readTextFile(path);
+    return await (await import("node:fs/promises")).readFile(path, "utf8");
+  } catch (error: any) {
+    if (error?.name === "NotFound" || error?.code === "ENOENT") return undefined;
+    throw error;
+  }
+}
