+import { assertEquals, assertRejects } from "@std/assert";
+import { test } from "@cliffy/internal/testing/test";
+import {
+  Command,
+  ConfigParseError,
+  ConfigValidationError,
+} from "../../mod.ts";
+
+async function withConfig(
+  files: Record<string, string>,
+  callback: (directory: string) => Promise<void>,
+) {
+  const directory = await Deno.makeTempDir();
+  try {
+    await Promise.all(Object.entries(files).map(([name, content]) =>
+      Deno.writeTextFile(`${directory}/${name}`, content)
+    ));
+    await callback(directory);
+  } finally {
+    await Deno.remove(directory, { recursive: true });
+  }
+}
+
+test("[command] - config - loads JSON values and honors precedence", async () => {
+  await withConfig({ "app.json": '{"port": 0, "enabled": false}' }, async (directory) => {
+    const command = new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [directory] })
+      .option("--port <port:number>", "...")
+      .option("--enabled", "...")
+      .env("PORT=<port:number>", "...");
+
+    const fromConfig = await command.parse([]);
+    assertEquals(fromConfig.options, { port: 0, enabled: false });
+    assertEquals(command.getConfigValues(), { port: 0, enabled: false });
+    assertEquals(command.getConfigPath(), `${directory}/app.json`);
+
+    Deno.env.set("PORT", "2");
+    try {
+      const fromEnv = await command.parse([]);
+      assertEquals(fromEnv.options.port, 2);
+      const fromCli = await command.parse(["--port", "3"]);
+      assertEquals(fromCli.options.port, 3);
+    } finally {
+      Deno.env.delete("PORT");
+    }
+  });
+});
+
+test("[command] - config - loads RC files and camel-cases keys", async () => {
+  await withConfig({ ".apprc": '# a comment\
