count=2\
' }, async (directory) => {
+    const result = await new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [directory] })
+      .option("--user-name <name>", "...")
+      .option("--count <count:number>", "...")
+      .parse([]);
+    assertEquals(result.options, { userName: "Ada Lovelace", count: 2 });
+  });
+});
+
+test("[command] - config - flattens JSON and merges paths in priority order", async () => {
